import React, { useState, useEffect, useRef } from "react";
import { Link, useLocation } from "react-router-dom";
import axios from "axios";

const Navbar = () => {
  const [categories, setCategories] = useState([]);
  const [showDropdown, setShowDropdown] = useState(false);
  const [loading, setLoading] = useState(true);
  const hideTimeout = useRef(null);

  const location = useLocation();
  const isHome = location.pathname === "/"; 

  const API_BASE_URL = "http://localhost:5000/api";

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/categories`);
      setCategories(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      console.error(err);
      setCategories([]);
    } finally {
      setLoading(false);
    }
  };

  const handleMouseEnter = () => {
    if (hideTimeout.current) clearTimeout(hideTimeout.current);
    setShowDropdown(true);
  };

  const handleMouseLeave = () => {
    hideTimeout.current = setTimeout(() => {
      setShowDropdown(false);
    }, 150);
  };

  return (
    <>
      <nav
        className={`
          w-full bg-[#1e293b] text-white shadow-md z-40
          ${isHome ? "relative" : "fixed top-[118px] left-0"}
        `}
      >
        <div className="max-w-7xl mx-auto flex justify-center py-3 px-6">
          <ul className="flex items-center justify-around gap-10 text-lg font-medium">

            <li>
              <Link to="/" className="hover:text-[#f472b6]">Trang chủ</Link>
            </li>

            <li>
              <Link to="/product" className="hover:text-[#f472b6]">Sản phẩm</Link>
            </li>

            {/* Danh mục */}
            <li
              className="relative"
              onMouseEnter={handleMouseEnter}
              onMouseLeave={handleMouseLeave}
            >
              <button className="flex items-center gap-1 hover:text-[#f472b6]">
                Danh mục <span className="text-sm">▼</span>
              </button>

              {showDropdown && (
                <div
                  className="absolute top-full left-1/2 -translate-x-1/2 bg-white 
                             border border-gray-200 shadow-xl rounded-xl mt-2 
                             w-64 z-50 animate-fadeIn"
                >
                  {loading ? (
                    <div className="p-4 text-center text-gray-500 text-sm">Đang tải...</div>
                  ) : (
                    <ul className="max-h-80 overflow-y-auto">
                      {categories.map((c) => (
                        <li key={c._id}>
                          <Link
                            to={`/category/${c.slug}`}
                            className="block px-4 py-2 text-gray-800 
                                       hover:bg-[#fde7f1] hover:text-[#d9467a] rounded-md"
                          >
                            {c.name}
                          </Link>
                        </li>
                      ))}

                      <li className="border-t border-gray-200">
                        <Link
                          to="/product"
                          className="block px-4 py-3 text-center text-[#d9467a] font-semibold hover:underline"
                        >
                          Xem tất cả
                        </Link>
                      </li>
                    </ul>
                  )}
                </div>
              )}
            </li>

            <li>
              <Link to="/about" className="hover:text-[#f472b6]">Giới thiệu</Link>
            </li>

            <li>
              <Link to="/contact" className="hover:text-[#f472b6]">Liên hệ</Link>
            </li>
          </ul>
        </div>
      </nav>

      {/* Chống chèn nội dung */}
      {!isHome && <div className="h-[58px]"></div>}
    </>
  );
};

export default Navbar;
